insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('17370', 'da.hu.lu', 'dahulu', '', '', '["Nomina","Adverbia","Adverbia","Adverbia"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"(waktu) yang telah lalu; (masa) lampau","contoh":[{"nomor":2,"teks":"lain -- lain sekarang"}]},{"nomor":"2","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"lebih awal; paling depan","contoh":[{"nomor":2,"teks":"-- bajak daripada jawi"}]},{"nomor":"3","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"yang mula-mula (dikerjakan, diperbuat, dan sebagainya); dulu","contoh":[{"nomor":2,"teks":"-- membaca, lalu menulis"},{"nomor":4,"teks":"silakan duduk --"}]},{"nomor":"4","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"lebih awal; sebelum","contoh":[{"nomor":2,"teks":"terlebih -- saya ucapkan terima kasih"},{"nomor":4,"teks":"-- daripada itu"}]}]', null, '["berdahulu-dahuluan","bersidahulu","dahulu-mendahului","kedahuluan","keterdahuluan","mendahului","mendahulukan","pendahulu","pendahuluan","terdahulu","terdahului"]', '["dahulu kala"]', '["bak menanti orang dahulu, bak melalah orang kudian","berguru dahulu sebelum bergurau","dahulu bajak daripada jawi","dahulu duduk dari cangkung","dahulu elang pulau, kini telah menjadi burung pungguk","dahulu timah, sekarang besi","kalau sorok lebih dahulu daripada tokok, tidak mati babi","kata dahulu bertepati, kata kemudian kata bercari","mensiang yang baru dicari, kampil ‘lah sudah dahulu","pahit dahulu, manis kemudian","pikir dahulu pendapatan, sesal kemudian tidak berguna","sedap dahulu, pahit kemudian","sesal (pikir) dahulu pendapatan, sesal kemudian tidak berguna","sesal dahulu yang bertuah, sesal kemudian yang celaka","seperti batang mengkudu, dahulu buah daripada bunga","seperti menanti orang dahulu, mengejar orang kemudian"]', '[]', '[{"peribahasa":"bak menanti orang dahulu, bak melalah orang kudian","makna":"melakukan sesuatu yang sia-sia"},{"peribahasa":"berguru dahulu sebelum bergurau","makna":"hendaknya belajar atau menuntut ilmu terlebih dahulu sebelum bersenang-senang atau melakukan hal-hal yang bersifat santai"},{"peribahasa":"dahulu bajak daripada jawi","makna":"sesuatu yang seharusnya didahulukan malah dikemudiankan, dan sebaliknya; tidak mengikuti aturan yang biasa"},{"peribahasa":"dahulu duduk dari cangkung","makna":"beranggapan sudah memiliki sesuatu yang belum tentu diperoleh"},{"peribahasa":"dahulu elang pulau, kini telah menjadi burung pungguk","makna":"seseorang yang sudah turun derajat atau turun pangkat"},{"peribahasa":"dahulu timah, sekarang besi","makna":"seseorang yang turun martabatnya atau kedudukannya"},{"peribahasa":"kalau sorok lebih dahulu daripada tokok, tidak mati babi","makna":"jika hanya mengandalkan lagak atau bual (omong besar) yang didahulukan tanpa disertai tindakan nyata, maka maksud atau tujuan yang diinginkan tidak akan tercapai"},{"peribahasa":"kata dahulu bertepati, kata kemudian kata bercari","makna":"janji yang telah dibuat harus ditepati. Jika ada hal baru yang muncul kemudian, hal tersebut harus dimusyawarahkan atau disepakati kembali"},{"peribahasa":"mensiang yang baru dicari, kampil ‘lah sudah dahulu","makna":"suatu keputusan telah diambil terlebih dahulu sebelum perundingan atau pembahasan dimulai"},{"peribahasa":"pahit dahulu, manis kemudian","makna":"mendisiplinkan diri pada masa sekarang untuk mencapai hasil yang baik di masa depan"},{"peribahasa":"pikir dahulu pendapatan, sesal kemudian tidak berguna","makna":"setiap tindakan atau perbuatan hendaknya dipikirkan baik-baik terlebih dahulu sebelum dikerjakan agar tidak timbul penyesalan di kemudian hari"},{"peribahasa":"sedap dahulu, pahit kemudian","makna":"bersenang-senang dahulu, tetapi akhirnya akan mendapatkan kesusahan"},{"peribahasa":"sesal (pikir) dahulu pendapatan, sesal kemudian tidak berguna","makna":"setiap tindakan atau perbuatan hendaknya dipikirkan baik-baik terlebih dahulu sebelum dikerjakan agar tidak timbul penyesalan di kemudian hari"},{"peribahasa":"sesal dahulu yang bertuah, sesal kemudian yang celaka","makna":"setiap perbuatan atau tindakan hendaknya dipikirkan dan dipertimbangkan secara matang terlebih dahulu agar tidak menimbulkan penyesalan di kemudian hari"},{"peribahasa":"seperti batang mengkudu, dahulu buah daripada bunga","makna":"perihal orang yang lekas/cepat marah sebelum mengetahui benar kesalahan orang yang hendak dimarahinya"},{"peribahasa":"seperti menanti orang dahulu, mengejar orang kemudian","makna":"perbuatan yang sia-sia"}]');
