insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('17457', 'da.lam', 'dalam', '', '', '["Adjektiva","Adjektiva","Adjektiva","kiasan","Adjektiva","Adjektiva","Nomina","Nomina","Adjektiva","Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"jauh ke bawah (dari permukaan); jauh masuk ke tengah (dari tepi)","contoh":[{"nomor":2,"teks":"lukanya cukup --"}]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"paham benar-benar (tentang ilmu pengetahuan dan sebagainya)","contoh":[]},{"nomor":"3","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"sampai ke lubuk hati; betul-betul terasakan di hati (tentang cinta, dendam, penderitaan, sakit hati)","contoh":[{"nomor":2,"teks":"cintanya kepada gadis itu sangat --"}]},{"nomor":"4","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"mengandung makna (maksud) yang sukar dipahami (tentang perkataan)","contoh":[{"nomor":2,"teks":"perkataan ini -- maknanya"}]},{"nomor":"5","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"mengandung arti (maksud tertentu)","contoh":[{"nomor":2,"teks":"kata-kata yang diucapkan kepadamu cukup --"}]},{"nomor":"6","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bagian yang di dalam, bukan bagian luar","contoh":[{"nomor":2,"teks":"ketika rumah itu terbakar, anak-anaknya masih ada di --"}]},{"nomor":"7","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"lingkungan daerah (negeri, keluarga) sendiri","contoh":[{"nomor":2,"teks":"orang --"},{"nomor":4,"teks":"urusan --"}]},{"nomor":"8","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"jeluk","contoh":[{"nomor":2,"teks":"piring --"}]},{"nomor":"9","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"batin","contoh":[]},{"nomor":"10","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"yang tidak tampak dari luar (tentang penyakit dan sebagainya)","contoh":[{"nomor":2,"teks":"penyakit --"}]}]', null, '["berdalam-dalam","berkedalaman","dalam-dalam","dalaman","kedalaman","kemendalaman","memperdalam","memperdalami","mendalam","mendalami","mendalamkan","pedalaman","pendalaman","sedalam-dalam","sedalam-dalamnya","semendalam","terdalam"]', '["dalam negeri","kedalaman kompensasi kalsit","dalam jaringan","dalam jejaring","dalam pada itu","dalam peninggal"]', '["ada beras, taruh dalam padi","ada kambing yang hitam dalam setiap kumpulannya","adapun manikam itu jika dijatuhkan ke dalam limbahan sekalipun, niscaya tidak hilang cahayanya","air beriak tanda tak dalam","air dalam karang menonggok, setanggi campur kemenyan, gula tertumpah pada kanji","anak dipangku dilepaskan, beruk dalam rimba disusukan (disusui)","apa gunanya bulan terang di dalam hutan, jikalau di dalam negeri betapa baiknya","asam di darat, ikan di laut (garam di laut asam di gunung) bertemu dalam belanga","ayam tidur senang dalam reban, musang yang susah beredar keliling","bagai buah keras dalam sekul","bagai burung dalam sangkar emas","bagai duri dalam daging","bagai enau dalam belukar, melepaskan pucuk masing-masing","bagai ikan dalam keroncong","bagai menghela rambut dalam tepung","batu yang bergolek dalam sungai, tiada dihinggapi lumut","beriak tanda tak dalam, berguncang tanda tak penuh","berkelahi bagai laba-laba dalam gelas","berkelahi dalam kepuk","berkelahi dalam mimpi","dalam berselam, dangkal berjingkat","dalam laut boleh diajuk, dalam hati siapa tahu","dalam madu berisi empedu","dalam rumah membuat rumah","dangkal telah keseberangan, dalam telah keajukan","di luar bagai madu, di dalam bagai empedu","di luar harimau, di dalam kambing","di luar merah, di dalam pahit","diuji sama merah, dalam hati (ditail) sama berat","duduk di dalam tabir, langit-langit berbau tembelang","duri dalam daging","elok kata dalam mufakat, buruk kata di luar mufakat","garam di laut, asam di gunung bertemu dalam belanga juga","gula di mulut, ikan dalam belanga","gunting makan di dalam","hilang ikan dalam kerabu","hilang kilat dalam kilau","ikan di laut, asam di gunung, bertemu dalam belanga","ikan lagi di laut, lada garam sudah dalam sengkalan","kain dalam acar","kain dalam lipatan","kelik-kelik dalam baju","kilat di dalam kilau","lubuk dalam, si kitang yang empunya","mandi dalam cupak","manis mulutnya bercakap seperti sautan manisan, di dalam bagai empedu","masak di luar, mentah di dalam","masuk dalam kawanan gajah berdering","memahat di dalam baris, berkata dalam pusaka","memancing dalam belanga","membeli kucing dalam karung","memepas dalam belanga","mencari jejak dalam air","mencari kutu dalam ijuk","mencari umbut dalam batu","menerka ayam di dalam telur","mengail dalam belanga, menggunting dalam lipatan","mengembalikan manikam ke dalam cembulnya","menggunting dalam lipatan","menohok kawan seiring, menggunting dalam lipatan","menyelami air dalam tonggak","menyenduk kuah dalam pengat","musuh dalam selimut","pelanduk di cerang rimba (pelanduk di dalam cerang)","pelanduk di dalam cerang (di cerang rimba)","pepat di luar, pancung di dalam","pepat di luar, rancung (pancunya) di dalam","semisal udang dalam tangguk","seperti api dalam sekam","seperti air dalam kolam","seperti air dalam talam","seperti api makan (di dalam) sekam","seperti buah kedempung, di luar berisi di dalam kosong","seperti gula dalam mulut","seperti ikan dalam air","seperti ikan dalam belat","seperti ikan dalam tebat","seperti menangkap ikan dalam belanga","seperti sebuah biji tersesat dalam rumput","seperti tabuhan di dalam tukil","tahu di dalam lubuk","taruh beras dalam padi","teluknya dalam, rantaunya sakti","tempayan tertiarap dalam air","teralang-alang bagaikan sampah dalam mata","udang dalam tangguk"]', '["berteras ke dalam","bulan jatuh dalam ribaan","di dalam tangan","kambing dalam biduk","kasih bersabung dalam hati","mengukir dalam hati","tergores dalam hati"]', '[{"peribahasa":"ada beras, taruh dalam padi","makna":"semua rahasia harus dijaga dengan baik agar tidak bocor"},{"peribahasa":"ada kambing yang hitam dalam setiap kumpulannya","makna":"dalam setiap kelompok atau keluarga, tidak semuanya baik, selalu ada satu atau beberapa individu yang memiliki perangai atau perilaku buruk"},{"peribahasa":"adapun manikam itu jika dijatuhkan ke dalam limbahan sekalipun, niscaya tidak hilang cahayanya","makna":"orang yang pada dasarnya baik, meskipun ia hidup dalam kemiskinan atau menjadi suruhan orang lain, sifat, perilaku, dan budi bahasanya akan tetap baik"},{"peribahasa":"air beriak tanda tak dalam","makna":"orang yang banyak bicara atau bersikap sombong, biasanya tidak memiliki banyak ilmu atau pengetahuan yang mendalam"},{"peribahasa":"air dalam karang menonggok, setanggi campur kemenyan, gula tertumpah pada kanji","makna":"suatu usaha yang berhasil dicapai dengan baik"},{"peribahasa":"anak dipangku dilepaskan, beruk dalam rimba disusukan (disusui)","makna":"selalu mengurusi atau memikirkan urusan orang lain, sementara urusan sendiri diabaikan atau tidak dipedulikan"},{"peribahasa":"apa gunanya bulan terang di dalam hutan, jikalau di dalam negeri betapa baiknya","makna":"tidak ada faedahnya menunjukkan kepandaian atau kelebihan diri kepada orang-orang yang tidak dapat menghargainya atau tidak memahami nilai dari kepandaian tersebut"},{"peribahasa":"asam di darat, ikan di laut (garam di laut asam di gunung) bertemu dalam belanga","makna":"laki-laki dan perempuan, jika sudah berjodoh, pada akhirnya akan bertemu juga, meskipun mereka berasal dari tempat yang berjauhan atau memiliki latar belakang yang berbeda"},{"peribahasa":"ayam tidur senang dalam reban, musang yang susah beredar keliling","makna":"orang yang berperasaan dengki atau cemburu, tidak suka melihat orang lain hidup bahagia atau senang"},{"peribahasa":"bagai buah keras dalam sekul","makna":"berbicara dalam keadaan tergopoh-gopoh atau kelam kabut pertuturan"},{"peribahasa":"bagai burung dalam sangkar emas","makna":"seseorang yang hidupnya mewah dan bergelimang harta, namun merasa terkekang, tidak bebas, dan tidak bahagia"},{"peribahasa":"bagai duri dalam daging","makna":"Sesuatu yang selalu menyakitkan hati dan mengganggu pikiran."},{"peribahasa":"bagai enau dalam belukar, melepaskan pucuk masing-masing","makna":"mementingkan diri sendiri dan tidak bersepakat atau tiada permuafakatan dalam masyarakat atau suatu perbincangan"},{"peribahasa":"bagai ikan dalam keroncong","makna":"tidak tertolong lagi"},{"peribahasa":"bagai menghela rambut dalam tepung","makna":"melakukan suatu pekerjaan yang sulit dan rumit dengan sangat hati-hati dan cermat, sehingga tidak menimbulkan kerusakan atau kerugian pada pihak manapun"},{"peribahasa":"batu yang bergolek dalam sungai, tiada dihinggapi lumut","makna":"orang yang suka berpindah-pindah pekerjaan atau tidak tetap dalam satu bidang, tidak akan mencapai kemajuan atau kekayaan dalam hidupnya"},{"peribahasa":"beriak tanda tak dalam, berguncang tanda tak penuh","makna":"orang yang sombong, banyak bicara tetapi tidak berisi atau tidak berilmu"},{"peribahasa":"berkelahi bagai laba-laba dalam gelas","makna":"perkelahian yang sangat hebat di tempat yang sangat sempit"},{"peribahasa":"berkelahi dalam kepuk","makna":"suatu masalah atau perkara yang sulit diselesaikan"},{"peribahasa":"berkelahi dalam mimpi","makna":"berlelah-lelah dengan sia-sia"},{"peribahasa":"dalam berselam, dangkal berjingkat","makna":"pandai menyesuaikan diri atau penghasilan yang dipadakan/dicukupkan"},{"peribahasa":"dalam laut boleh diajuk, dalam hati siapa tahu","makna":"apa yang tersembunyi di dalam hati seseorang tidak dapat kita ketahui atau duga"},{"peribahasa":"dalam madu berisi empedu","makna":"Seseorang yang kelihatannya baik, tetapi sebenarnya berhati jahat."},{"peribahasa":"dalam rumah membuat rumah","makna":"Mencari keuntungan untuk diri sendiri dari harta atau usaha orang lain."},{"peribahasa":"dangkal telah keseberangan, dalam telah keajukan","makna":"Telah mengetahui segala seluk beluk suatu perkara."},{"peribahasa":"di luar bagai madu, di dalam bagai empedu","makna":"Penampilan luar yang baik dan manis, tetapi hatinya jahat."},{"peribahasa":"di luar harimau, di dalam kambing","makna":"Terlihat gagah dan berani di luar, tetapi sebenarnya penakut."},{"peribahasa":"di luar merah, di dalam pahit","makna":"Tampak luar baik, tetapi di dalamnya buruk atau jahat."},{"peribahasa":"diuji sama merah, dalam hati (ditail) sama berat","makna":"Keadilan yang sejati, tidak memihak kepada siapapun."},{"peribahasa":"duduk di dalam tabir, langit-langit berbau tembelang","makna":"Kejahatan atau perbuatan buruk yang tersembunyi pada akhirnya akan terungkap juga."},{"peribahasa":"duri dalam daging","makna":"Sesuatu yang selalu menyakitkan hati dan mengganggu pikiran."},{"peribahasa":"elok kata dalam mufakat, buruk kata di luar mufakat","makna":"Keputusan yang diambil bersama akan lebih baik daripada keputusan yang diambil sendiri."},{"peribahasa":"garam di laut, asam di gunung bertemu dalam belanga juga","makna":"Laki-laki dan perempuan, jika sudah berjodoh, pada akhirnya akan bertemu juga, meskipun mereka berasal dari tempat yang berjauhan atau memiliki latar belakang yang berbeda."},{"peribahasa":"gula di mulut, ikan dalam belanga","makna":"Janji manis yang belum tentu ditepati."},{"peribahasa":"gunting makan di dalam","makna":"Musuh dalam selimut; orang yang merugikan dari dalam."},{"peribahasa":"hilang ikan dalam kerabu","makna":"Kehilangan sesuatu yang berharga karena kecerobohan."},{"peribahasa":"hilang kilat dalam kilau","makna":"Kepandaian atau kelebihan seseorang yang tidak terlihat karena berada di lingkungan orang-orang yang lebih pandai."},{"peribahasa":"ikan di laut, asam di gunung, bertemu dalam belanga","makna":"Laki-laki dan perempuan, jika sudah berjodoh, pada akhirnya akan bertemu juga, meskipun mereka berasal dari tempat yang berjauhan atau memiliki latar belakang yang berbeda."},{"peribahasa":"ikan lagi di laut, lada garam sudah dalam sengkalan","makna":"Bersiap-siap untuk merayakan sesuatu yang belum pasti didapat."},{"peribahasa":"kain dalam acar","makna":"Sesuatu yang sangat dihargai atau dijaga dengan baik."},{"peribahasa":"kain dalam lipatan","makna":"Sesuatu yang disembunyikan atau dirahasiakan."},{"peribahasa":"kelik-kelik dalam baju","makna":"Musuh dalam selimut; orang yang merugikan dari dalam."},{"peribahasa":"kilat di dalam kilau","makna":"Kepandaian atau kelebihan seseorang yang tidak terlihat karena berada di lingkungan orang-orang yang lebih pandai."},{"peribahasa":"lubuk dalam, si kitang yang empunya","makna":"Setiap tempat ada penguasanya."},{"peribahasa":"mandi dalam cupak","makna":"Hidup dalam serba kekurangan."},{"peribahasa":"manis mulutnya bercakap seperti sautan manisan, di dalam bagai empedu","makna":"Orang yang perkataannya manis tetapi hatinya jahat."},{"peribahasa":"masak di luar, mentah di dalam","makna":"Tampak baik di luar, tetapi sebenarnya buruk di dalam."},{"peribahasa":"masuk dalam kawanan gajah berdering","makna":"Mengikuti adat atau kebiasaan di tempat yang baru."},{"peribahasa":"memahat di dalam baris, berkata dalam pusaka","makna":"Melakukan sesuatu sesuai dengan adat dan kebiasaan yang berlaku."},{"peribahasa":"memancing dalam belanga","makna":"Mencari keuntungan dalam lingkungan sendiri."},{"peribahasa":"membeli kucing dalam karung","makna":"Membeli sesuatu tanpa mengetahui kualitasnya terlebih dahulu."},{"peribahasa":"memepas dalam belanga","makna":"Mencari keuntungan dalam lingkungan sendiri."},{"peribahasa":"mencari jejak dalam air","makna":"Melakukan pekerjaan yang sia-sia."},{"peribahasa":"mencari kutu dalam ijuk","makna":"Melakukan pekerjaan yang sia-sia dan tidak mungkin berhasil."},{"peribahasa":"mencari umbut dalam batu","makna":"Melakukan pekerjaan yang sia-sia dan tidak mungkin berhasil."},{"peribahasa":"menerka ayam di dalam telur","makna":"Menentukan sesuatu yang belum pasti."},{"peribahasa":"mengail dalam belanga, menggunting dalam lipatan","makna":"Mencari keuntungan dalam lingkungan sendiri."},{"peribahasa":"mengembalikan manikam ke dalam cembulnya","makna":"Memperbaiki sesuatu yang salah atau rusak."},{"peribahasa":"menggunting dalam lipatan","makna":"Mencelakakan kawan sendiri."},{"peribahasa":"menohok kawan seiring, menggunting dalam lipatan","makna":"Mencelakakan teman sendiri dari belakang."},{"peribahasa":"menyelami air dalam tonggak","makna":"Meskipun pandai, tetapi jika tidak berhati-hati akan celaka juga."},{"peribahasa":"menyenduk kuah dalam pengat","makna":"Mencari keuntungan dari keluarga atau teman sendiri."},{"peribahasa":"musuh dalam selimut","makna":"Orang dekat yang berkhianat."},{"peribahasa":"pelanduk di cerang rimba (pelanduk di dalam cerang)","makna":"Orang yang merasa terancam atau ketakutan."},{"peribahasa":"pelanduk di dalam cerang (di cerang rimba)","makna":"Orang yang merasa terancam atau ketakutan."},{"peribahasa":"pepat di luar, pancung di dalam","makna":"Tampak baik di luar, tetapi sebenarnya buruk di dalam."},{"peribahasa":"pepat di luar, rancung (pancunya) di dalam","makna":"Tampak baik di luar, tetapi sebenarnya buruk di dalam."},{"peribahasa":"semisal udang dalam tangguk","makna":"Tidak dapat bergerak bebas."},{"peribahasa":"seperti api dalam sekam","makna":"Sesuatu yang berbahaya tetapi tidak terlihat."},{"peribahasa":"seperti air dalam kolam","makna":"Tenang dan tidak bergejolak."},{"peribahasa":"seperti air dalam talam","makna":"Tenang dan tidak bergejolak."},{"peribahasa":"seperti api makan (di dalam) sekam","makna":"Sesuatu yang berbahaya tetapi tidak terlihat."},{"peribahasa":"seperti buah kedempung, di luar berisi di dalam kosong","makna":"Orang yang tampak kaya atau berilmu, tetapi sebenarnya tidak."},{"peribahasa":"seperti gula dalam mulut","makna":"Sesuatu yang sangat mudah didapatkan."},{"peribahasa":"seperti ikan dalam air","makna":"Sangat lincah dan bebas."},{"peribahasa":"seperti ikan dalam belat","makna":"Tidak dapat bergerak bebas."},{"peribahasa":"seperti ikan dalam tebat","makna":"Sangat mudah didapatkan."},{"peribahasa":"seperti menangkap ikan dalam belanga","makna":"Melakukan pekerjaan yang sangat mudah."},{"peribahasa":"seperti sebuah biji tersesat dalam rumput","makna":"Sesuatu yang sangat kecil dan sulit ditemukan."},{"peribahasa":"seperti tabuhan di dalam tukil","makna":"Sangat berisik dan mengganggu."},{"peribahasa":"tahu di dalam lubuk","makna":"Mengetahui rahasia atau seluk beluk suatu perkara."},{"peribahasa":"taruh beras dalam padi","makna":"Menyimpan rahasia dengan baik."},{"peribahasa":"teluknya dalam, rantaunya sakti","makna":"Orang yang memiliki ilmu atau kesaktian yang tinggi."},{"peribahasa":"tempayan tertiarap dalam air","makna":"Tidak ada gunanya."},{"peribahasa":"teralang-alang bagaikan sampah dalam mata","makna":"Sesuatu yang sangat mengganggu."},{"peribahasa":"udang dalam tangguk","makna":"Tidak dapat bergerak bebas."}]');
