insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('17742', 'da.pat', 'dapat', '', '', '["Adverbia","Verba","Cakapan","Verba","Verba","Verba","Cakapan"]', '[{"nomor":"1","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"mampu; sanggup; bisa","contoh":[{"nomor":2,"teks":"serangan musuh tidak -- ditahan"},{"nomor":4,"teks":"isi hatinya tidak -- kita ketahui"}]},{"nomor":"2","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"}],"definisi":"menerima; memperoleh","contoh":[{"nomor":2,"teks":"pemuda yang membacok temannya itu -- hukuman penjara tiga bulan"}]},{"nomor":"3","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"ditemukan; tertangkap dan sebagainya","contoh":[{"nomor":2,"teks":"ke mana pun dicarinya, anting itu tidak -- juga"},{"nomor":4,"teks":"cari mereka sampai --"}]},{"nomor":"4","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"berhasil; tercapai (maksudnya dan sebagainya)","contoh":[{"nomor":2,"teks":"mudah-mudahan -- juga apa yang engkau cita-citakan"}]},{"nomor":"5","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"}],"definisi":"datang bulan; haid","contoh":[{"nomor":2,"teks":"dia terlihat murung, mungkin karena lagi --"}]}]', null, '["berdapat","berpendapat","berpendapatan","dapatan","kedapatan","keterdapatan","memperdapat","mendapat","mendapati","mendapatkan","pendapat","pendapatan","sedapat","sedapat-dapatnya","sedapatnya","sependapat","terdapat"]', '["dapat hati"]', '["air (yang) dingin juga dapat memadamkan api","air yang dingin juga yang dapat memadamkan api","angin tak dapat ditangkap, asap tak dapat digenggam","ayam dapat, musang pun dapat","bagai menyesah kain dapat","belalang dapat menuai","berebut buluh tamiang hanyut, tangan luka buluh tamiang tak dapat","biar telinga rabit, asal dapat bersubang","bingung tak dapat diajar, cerdik tak dapat diikuti","dapat durian runtuh","dapat kijang teruit","dapat tebu rebah","daun dapat dilayangkan, getah jatuh ke perdu juga","dekat dapat ditunjal, jauh dapat ditunjuk","dengan sesendok madu dapat lebih banyak ditangkap serangga daripada dengan cuka sesendok","habis umpan, kerong tak dapat","ikan belum dapat, airnya sudah keruh","ikan biar dapat, serampang jangan pokah","ikan biar dapat, serampang jangan pukah","isi lemak dapat ke orang, tulang bulu pulang ke kita","jauh dapat ditunjuk, dekat dapat ditunjal","jikalau di hulu airnya keruh, tak dapat tidak di hilirnya keruh juga","jikalau tidak dapat diperbaiki, janganlah dipecahkan","karam di laut dapat direnangi, karam di hati bilakan sudah","ke gunung tak dapat angin","kerbau seratus dapat digembalakan, manusia seorang tiada terkawal","kodok dapat bunga sekuntum","mahal dibeli, sukar dijual (mahal tak dapat dibeli, murah tak dapat diminta)","mati gajah tidak dapat belalainya, mati harimau tidak dapat belangnya","mulut kapuk dapat ditutup, mulut orang tidak","mulut tabuh dapat disumbat, mulut manusia bagaimana menyebutnya","pukat terlabuh, ikan tak dapat","rezeki elang tak akan dapat (dimakan) oleh musang (burung pipit)","sebagai kera dapat canggung","sendok berdengar-dengar, nasi habis budi dapat","sepasin dapat bersiang","siapa cepat, dia dapat","seperti api makan lalang kering, tiada dapat dipadamkan lagi","seperti bergendang ke Sirukam, emas dapat peruk kenyang","seperti cembul dengan tutupnya (dapat tutupnya)","seperti kera dapat bunga","sudah dapat gading bertuah, tanduk tiada berguna lagi","tali busur tidak selamanya dapat diregang","tanduk di kepala tak dapat digelengkan","telah dapat gading bertuah, terbuang tanduk kerbau mati","tersesak undang kepada yang runcing, tiada dapat bertenggang lagi","tohok raja tidak dapat dielakkan","tuba habis, ikan tak dapat","utang emas dapat dibayar, utang budi dibawa mati","yang dikandung berceceran, yang dikejar tiada dapat","yang dikejar tiada dapat, yang dikandung berceceran","yang dikejar tidak dapat, yang dikandung berceceran"]', '["dapat dihitung dengan jari","dapat dihitung jari"]', '[{"peribahasa":"air (yang) dingin juga dapat memadamkan api","makna":"tingkah laku dan budi bahasa yang lemah lembut dapat meredakan kemarahan seseorang"},{"peribahasa":"air yang dingin juga yang dapat memadamkan api","makna":"hanya perkataan atau tingkah laku yang lemah lembut yang dapat meredakan kemarahan seseorang"},{"peribahasa":"angin tak dapat ditangkap, asap tak dapat digenggam","makna":"rahasia tidak selamanya dapat disembunyikan, suatu saat akan terbongkar juga"},{"peribahasa":"ayam dapat, musang pun dapat","makna":"pencuri tertangkap, barang-barang yang dicuri pun didapatkan kembali"},{"peribahasa":"bagai menyesah kain dapat","makna":"Melakukan pekerjaan yang sia-sia atau tidak ada hasilnya."},{"peribahasa":"belalang dapat menuai","makna":"Mendapatkan keuntungan tanpa bersusah payah."},{"peribahasa":"berebut buluh tamiang hanyut, tangan luka buluh tamiang tak dapat","makna":"Berebut sesuatu yang tidak ada gunanya, akhirnya merugikan diri sendiri."},{"peribahasa":"biar telinga rabit, asal dapat bersubang","makna":"Meskipun harus menderita, asalkan tujuan tercapai."},{"peribahasa":"bingung tak dapat diajar, cerdik tak dapat diikuti","makna":"Orang yang tidak mau menerima nasihat atau tidak mau mengikuti kebaikan."},{"peribahasa":"dapat durian runtuh","makna":"Mendapatkan keuntungan besar secara tidak terduga."},{"peribahasa":"dapat kijang teruit","makna":"Mendapatkan sesuatu yang diinginkan dengan mudah."},{"peribahasa":"dapat tebu rebah","makna":"Mendapatkan keuntungan tanpa bersusah payah."},{"peribahasa":"daun dapat dilayangkan, getah jatuh ke perdu juga","makna":"Meskipun seseorang pergi jauh, ia akan kembali ke asalnya."},{"peribahasa":"dekat dapat ditunjal, jauh dapat ditunjuk","makna":"Sesuatu yang mudah dijangkau atau diketahui."},{"peribahasa":"dengan sesendok madu dapat lebih banyak ditangkap serangga daripada dengan cuka sesendok","makna":"Kebaikan akan lebih mudah menarik orang daripada kekerasan."},{"peribahasa":"habis umpan, kerong tak dapat","makna":"Sudah berusaha keras, tetapi tidak mendapatkan hasil."},{"peribahasa":"ikan belum dapat, airnya sudah keruh","makna":"Sudah membuat keributan sebelum mencapai tujuan."},{"peribahasa":"ikan biar dapat, serampang jangan pokah","makna":"Mencapai tujuan tanpa merusak alat atau cara yang digunakan."},{"peribahasa":"ikan biar dapat, serampang jangan pukah","makna":"Mencapai tujuan tanpa merusak alat atau cara yang digunakan."},{"peribahasa":"isi lemak dapat ke orang, tulang bulu pulang ke kita","makna":"Orang lain yang menikmati hasilnya, kita yang menanggung kerugiannya."},{"peribahasa":"jauh dapat ditunjuk, dekat dapat ditunjal","makna":"Sesuatu yang mudah dijangkau atau diketahui."},{"peribahasa":"jikalau di hulu airnya keruh, tak dapat tidak di hilirnya keruh juga","makna":"Jika pemimpinnya tidak baik, maka rakyatnya juga akan terpengaruh."},{"peribahasa":"jikalau tidak dapat diperbaiki, janganlah dipecahkan","makna":"Jika tidak bisa memperbaiki sesuatu, janganlah merusaknya."},{"peribahasa":"karam di laut dapat direnangi, karam di hati bilakan sudah","makna":"Kesulitan materi dapat diatasi, tetapi kesulitan batin sulit disembuhkan."},{"peribahasa":"ke gunung tak dapat angin","makna":"Tidak mendapatkan hasil apa-apa."},{"peribahasa":"kerbau seratus dapat digembalakan, manusia seorang tiada terkawal","makna":"Lebih mudah mengatur banyak hewan daripada satu manusia."},{"peribahasa":"kodok dapat bunga sekuntum","makna":"Mendapatkan sesuatu yang tidak sesuai dengan dirinya."},{"peribahasa":"mahal dibeli, sukar dijual (mahal tak dapat dibeli, murah tak dapat diminta)","makna":"Sesuatu yang sangat berharga dan sulit didapatkan."},{"peribahasa":"mati gajah tidak dapat belalainya, mati harimau tidak dapat belangnya","makna":"Orang besar atau terkenal akan selalu dikenang jasa-jasanya."},{"peribahasa":"mulut kapuk dapat ditutup, mulut orang tidak","makna":"Sulit membungkam perkataan orang lain."},{"peribahasa":"mulut tabuh dapat disumbat, mulut manusia bagaimana menyebutnya","makna":"Sulit membungkam perkataan orang lain."},{"peribahasa":"pukat terlabuh, ikan tak dapat","makna":"Sudah berusaha keras, tetapi tidak mendapatkan hasil."},{"peribahasa":"rezeki elang tak akan dapat (dimakan) oleh musang (burung pipit)","makna":"Setiap orang memiliki rezekinya masing-masing."},{"peribahasa":"sebagai kera dapat canggung","makna":"Mendapatkan sesuatu yang tidak berguna atau tidak sesuai."},{"peribahasa":"sendok berdengar-dengar, nasi habis budi dapat","makna":"Mendapatkan keuntungan dari hasil kerja keras orang lain."},{"peribahasa":"sepasin dapat bersiang","makna":"Mendapatkan kesempatan untuk berbuat sesuatu."},{"peribahasa":"siapa cepat, dia dapat","makna":"Siapa yang lebih dulu berusaha, dia yang akan mendapatkan hasil."},{"peribahasa":"seperti api makan lalang kering, tiada dapat dipadamkan lagi","makna":"Sesuatu yang sudah tidak dapat dihentikan lagi."},{"peribahasa":"seperti bergendang ke Sirukam, emas dapat peruk kenyang","makna":"Mendapatkan keuntungan besar tanpa bersusah payah."},{"peribahasa":"seperti cembul dengan tutupnya (dapat tutupnya)","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti kera dapat bunga","makna":"Mendapatkan sesuatu yang tidak berguna atau tidak sesuai."},{"peribahasa":"sudah dapat gading bertuah, tanduk tiada berguna lagi","makna":"Sudah mendapatkan yang lebih baik, yang lama tidak terpakai lagi."},{"peribahasa":"tali busur tidak selamanya dapat diregang","makna":"Kesabaran seseorang ada batasnya."},{"peribahasa":"tanduk di kepala tak dapat digelengkan","makna":"Sesuatu yang sudah menjadi takdir tidak dapat dihindari."},{"peribahasa":"telah dapat gading bertuah, terbuang tanduk kerbau mati","makna":"Sudah mendapatkan yang lebih baik, yang lama tidak terpakai lagi."},{"peribahasa":"tersesak undang kepada yang runcing, tiada dapat bertenggang lagi","makna":"Sudah tidak ada pilihan lain."},{"peribahasa":"tohok raja tidak dapat dielakkan","makna":"Perintah atau keputusan atasan tidak dapat dibantah."},{"peribahasa":"tuba habis, ikan tak dapat","makna":"Sudah berusaha keras, tetapi tidak mendapatkan hasil."},{"peribahasa":"utang emas dapat dibayar, utang budi dibawa mati","makna":"Kebaikan seseorang tidak akan pernah terlupakan."},{"peribahasa":"yang dikandung berceceran, yang dikejar tiada dapat","makna":"Sesuatu yang sudah ada di tangan hilang, sedangkan yang dicari tidak didapat."},{"peribahasa":"yang dikejar tiada dapat, yang dikandung berceceran","makna":"Sesuatu yang sudah ada di tangan hilang, sedangkan yang dicari tidak didapat."},{"peribahasa":"yang dikejar tidak dapat, yang dikandung berceceran","makna":"Sesuatu yang sudah ada di tangan hilang, sedangkan yang dicari tidak didapat."}]');
