"definisi":"kata untuk menyatakan perbandingan","contoh":[{"nomor":2,"teks":"harganya lebih mahal -- emas"}]},{"nomor":"9","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"}],"definisi":"kata depan untuk menyatakan pencegahan, pemindahan, atau pemisahan","contoh":[{"nomor":2,"teks":"jauhkan dirimu -- perbuatan itu"},{"nomor":4,"teks":"menghindarkan diri -- bahaya maut"}]},{"nomor":"10","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"}],"definisi":"kata depan untuk menyatakan kepunyaan","contoh":[{"nomor":2,"teks":"pidato pelantikan anggota DPR baru -- Presiden akan disiarkan melalui radio"}]},{"nomor":"11","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"}],"definisi":"melalui; melewati","contoh":[{"nomor":2,"teks":"ia masuk -- pintu belakang"}]}]', null, '["sedari"]', '["dari hati ke hati","dari mana","dari sana","dari sini","dari situ","dari tadi"]', '["bagai menakik darah mati dari alu (bagai menakik darah mati dari batu)","baju indah dari balai, tiba di rumah menyarungkan","berbilang dari esa, mengaji dari alif","buah jatuh tak jauh dari pohonnya","bukan air muara yang ditimba, sudah disauk dari hulunya","dahulu duduk dari cangkung","dari ajung turun ke sampan","dari jauh orang angkat telunjuk, kalau dekat dia angkat mata","dari jung turun ke sampan","dari lecah lari ke duri","dari semak ke belukar","dari telaga yang jernih tak akan mengalir air yang keruh","habis cupak oleh (dari) pelelehan","ikan busuk mulai dari kepala","indah kabar dari rupa","jauh panggang dari api","ke mana tumpah hujan dari bubungan, kalau tidak ke cucuran atap","kucing melompat, orang terkejut dari tidurnya, ayam berkokok, hari pun siang","lepas dari mulut harimau, jatuh ke mulut buaya","lewat dari manis, masam, lewat dari harum, busuk","lunak gigi dari lidah","masuk dari kuping kiri, keluar lewat kuping kanan","mulut manis jangan percaya, lepas dari tangan jangan diharap","rebung tidak jauh dari rumpun","seperti anak panah lepas dari busur","seperti bujuk lepas dari bubu","seperti kuda lepas dari pingitan","tak berasak lenggang dari ketiak","tak jauh rebung dari rumpunnya","tersisih antah dari beras"]', '["asalnya dari berkubak","dari mulut ke mulut","dari pintu ke pintu","jatuh dari langit","lolos dari lubang jarum","tidak lekang dari hati","titik dari mulutnya"]', '[{"peribahasa":"bagai menakik darah mati dari alu (bagai menakik darah mati dari batu)","makna":"Bekerja keras tetapi hasilnya sedikit."},{"peribahasa":"baju indah dari balai, tiba di rumah menyarungkan","makna":"hukuman sudah diputuskan dan tidak boleh dibanding lagi"},{"peribahasa":"berbilang dari esa, mengaji dari alif","makna":"jika mengerjakan sesuatu, hendaknya dimulai dari permulaan atau awal, tidak melompat-lompat, dan tidak terburu-buru"},{"peribahasa":"buah jatuh tak jauh dari pohonnya","makna":"sifat, tingkah laku, dan kebiasaan seorang anak tidak akan jauh berbeda dengan sifat, tingkah laku, dan kebiasaan orang tuanya"},{"peribahasa":"bukan air muara yang ditimba, sudah disauk dari hulunya","makna":"berita atau informasi yang didapatkan langsung dari sumber aslinya atau pangkalnya yang benar, bukan sekadar kabar bohong atau desas-desus"},{"peribahasa":"dahulu duduk dari cangkung","makna":"Beranggapan sudah memiliki sesuatu yang belum tentu diperoleh."},{"peribahasa":"dari ajung turun ke sampan","makna":"diturunkan pangkat atau jabatannya"},{"peribahasa":"dari jauh orang angkat telunjuk, kalau dekat dia angkat mata","makna":"diumpat atau dicaci maki karena perilaku yang tidak senonoh"},{"peribahasa":"dari jung turun ke sampan","makna":"turun pangkat atau turun martabat"},{"peribahasa":"dari lecah lari ke duri","makna":"berusaha menghindari masalah kecil, namun malah mendapatkan masalah yang lebih besar"},{"peribahasa":"dari semak ke belukar","makna":"meninggalkan sesuatu yang buruk, tetapi kemudian mendapatkan sesuatu yang sama buruknya atau bahkan lebih buruk"},{"peribahasa":"dari telaga yang jernih tak akan mengalir air yang keruh","makna":"dari sifat orang yang mulia atau baik, tidak akan muncul budi bahasa dan perilaku yang kasar atau tidak baik"},{"peribahasa":"habis cupak oleh (dari) pelelehan","makna":"adat atau peraturan yang dilanggar sedikit demi sedikit pada akhirnya akan dilanggar secara keseluruhan"},{"peribahasa":"ikan busuk mulai dari kepala","makna":"kegagalan atau kerusakan suatu sistem, organisasi, atau kelompok bermula dari pemimpinnya. Jika pemimpinnya bermasalah atau tidak becus, maka bawahannya atau anggota lainnya juga akan bermasalah atau ikut rusak"},{"peribahasa":"indah kabar dari rupa","makna":"berita yang tersebar biasanya lebih hebat atau dilebih-lebihkan daripada kenyataan yang sebenarnya"},{"peribahasa":"jauh panggang dari api","makna":"Sesuatu yang tidak sesuai dengan harapan atau kenyataan."},{"peribahasa":"ke mana tumpah hujan dari bubungan, kalau tidak ke cucuran atap","makna":"Sifat atau kebiasaan anak tidak jauh berbeda dengan orang tuanya."},{"peribahasa":"kucing melompat, orang terkejut dari tidurnya, ayam berkokok, hari pun siang","makna":"Sesuatu yang sudah menjadi kebiasaan atau rutinitas."},{"peribahasa":"lepas dari mulut harimau, jatuh ke mulut buaya","makna":"Terhindar dari satu bahaya, tetapi masuk ke bahaya yang lebih besar."},{"peribahasa":"lewat dari manis, masam, lewat dari harum, busuk","makna":"Sesuatu yang berlebihan akan menjadi tidak baik."},{"peribahasa":"lunak gigi dari lidah","makna":"Lebih mudah berbicara daripada melakukan."},{"peribahasa":"masuk dari kuping kiri, keluar lewat kuping kanan","makna":"Tidak memperhatikan nasihat atau perkataan orang lain."},{"peribahasa":"mulut manis jangan percaya, lepas dari tangan jangan diharap","makna":"Jangan mudah percaya pada janji manis, dan jangan berharap pada sesuatu yang sudah lepas."},{"peribahasa":"rebung tidak jauh dari rumpun","makna":"Sifat atau kebiasaan anak tidak jauh berbeda dengan orang tuanya."},{"peribahasa":"seperti anak panah lepas dari busur","makna":"Sesuatu yang sudah tidak dapat ditarik kembali."},{"peribahasa":"seperti bujuk lepas dari bubu","makna":"Seseorang yang berhasil melepaskan diri dari kesulitan."},{"peribahasa":"seperti kuda lepas dari pingitan","makna":"Seseorang yang merasa bebas setelah sekian lama terkekang."},{"peribahasa":"tak berasak lenggang dari ketiak","makna":"Tidak dapat dipisahkan."},{"peribahasa":"tak jauh rebung dari rumpunnya","makna":"Sifat atau kebiasaan anak tidak jauh berbeda dengan orang tuanya."},{"peribahasa":"tersisih antah dari beras","makna":"Memisahkan yang baik dari yang buruk."}]');
