sendiri"}]},{"nomor":"9","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"}],"definisi":"penghubung untuk menyatakan keselarasan (kesamaan, kesesuaian)","contoh":[{"nomor":2,"teks":"menyesuaikan -- keadaan lingkungan"},{"nomor":4,"teks":"mukanya mirip -- ibunya"}]}]', null, '[]', '["dengan demikian","dengan hormat","dengan kata lain","dengan pujian","dengan sendirinya"]', '["air susu dibalas dengan air tuba","anjing itu meski dirantai dengan rantai emas sekalipun, niscaya berulang-ulang juga ia ke tempat najis","arang itu jikalau dibasuh dengan air mawar sekalipun, tiada akan putih","bagai api dengan rabuk","bagai balam dengan ketitir","bagai beliung dengan asahan","bagai bertemu alu dengan lesung, beras kita yang terserak, ayam orang yang kenyang","bagai bulan dengan matahari","bagai dawat dengan kertas","bagai dulang dengan tudung saji","bagai ilak bercerai dengan benang","bagai inai dengan kuku","bagai kuku dengan daging","bagai kuku dengan isi","bagai menampung air dengan limas pesuk","berkata-kata dengan lutut","berkelahi dengan orang tak berambut","berlayar bernakhoda, berjalan dengan yang tua","bersawah seperempat piring, ke sawah sama dengan orang","bersisih antah dengan beras","bersua baji dengan matan (tahan baji oleh kelidai)","bersua beliung dengan sangkal","bersukat darah, bertimbang daging (dengan)","bertemu beliung dengan ruyung","bertemu muka dengan tedung","bertemu ruas dengan buku","bertemu teras dengan beliung","bertukar beruk dengan cigak","bertukar monyet dengan beruk","cakap berlauk(-lauk), makan dengan sambal lada","campak bunga dibalas dengan campak tahi","didenda dengan emas yang habis, dipancung dengan pedang yang hilang","dimandikan dengan air segeluk","dengan sesendok madu dapat lebih banyak ditangkap serangga daripada dengan cuka sesendok","duduk dengan sukatan","gigi dengan lidah, adakalanya bergigit juga","hidup sandar-menyandar umpama aur dengan tebing","hitam mata itu mana boleh bercerai dengan putihnya","jangan dekatkan panggang dengan kucing","jangan dicatuk dengan yang tajam, cincang dengan yang majal","kalau kena tampar, biar dengan tangan yang pakai cincin, kalau kena tendang, biar dengan kaki yang pakai kasut","kalau langit hendak menimpa bumi, bolehkah ditahan dengan telunjuk","kasih tidak bersekutu dengan baik","kepala tersangkut dengan kulit babi","ketemu baji dengan matan","kusut ujung dengan pangkalnya","malu-malu kucing, bujang dengan gadis","matahari itu bolehkah ditutup dengan nyiru","memakuk dengan punggung lading","membalas air susu dengan air tuba","membasuh muka dengan air liur","membasuh najis dengan malu","membungkus tulang dengan daun talas","memikat balam dengan balam","menangis daun bangun-bangun hendak sama dengan hilir air","menangkap gajah liar itu dengan gajah juga","mencungkil kuman dengan alu","mengaut laba dengan siku","menggaut laba dengan siku","mengikat manusia dengan akal, mengikat binatang dengan tali","menyisip padi dengan ilalang","minyak dengan air adakah (bolehkah) bercampur?","muka bagai ditampar dengan kulit babi","mulut disuapi pisang, pantat dikait dengan onak (mulut manis hati berkait)","padi dikebat dengan daunnya","padi segenggam dengan senang hati lebih baik daripada padi selumbung dengan bersusah hati","patah kemudi dengan bamnya","patah kemudi dengan ebamnya","pergi tempat bertanya, pulang tempat berberita (berkenaan dengan orang cerdik pandai)","pucuk diremas dengan santan, urat direndam dengan tengguli, lamun peria pahit juga","sebagai aur dengan tebing","sebagai dawat dengan kertas","sebagai garam dengan asam","sebagai kunyit dengan kapur","sebagai minyak dengan air","sedatar saja lurah dengan bukit","sendok dan periuk lagi berantuk (sendok dengan belanga lagi berlaga)","sepantun elang dengan ayam, lambat laun akan disambar jua","sepantun elang dengan ayam, lambat laun disambar juga","serigala dengan anggur","seukur mata dengan telinga","seperti anjing dengan kucing","seperti birah dengan keladi","seperti cembul dengan tutupnya (dapat tutupnya)","seperti cincin dengan permata","seperti daun delima dengan bunganya","seperti durian dengan mentimun","seperti gajah dengan sengkelanya","seperti garuk dengan sisir","seperti gerup dengan sisir","seperti kedangkan dengan caping","seperti kera dengan monyet","seperti keroncor dengan belangkas","seperti lepat dengan daun","seperti mentimun dengan durian","seperti pinggan dengan mangkuk, salah sedikit, hendak berantuk","seperti rabuk dengan api","seperti santan dengan tengguli","seperti sayur dengan rumput","seperti siang dengan malam","susu dibalas dengan tuba","tangguk lerek dengan bingkainya","tentang mata dengan mata (antara empat mata)"]', '["bagai minyak dengan air","dapat dihitung dengan jari","dengan keringatnya sendiri","seperti api dengan asap","seperti bumi dengan langit","seperti tudung saji dengan delamaknya"]', '[{"peribahasa":"air susu dibalas dengan air tuba","makna":"Kebaikan dibalas dengan kejahatan."},{"peribahasa":"anjing itu meski dirantai dengan rantai emas sekalipun, niscaya berulang-ulang juga ia ke tempat najis","makna":"Sifat buruk seseorang sulit diubah."},{"peribahasa":"arang itu jikalau dibasuh dengan air mawar sekalipun, tiada akan putih","makna":"Sifat buruk seseorang sulit diubah."},{"peribahasa":"bagai api dengan rabuk","makna":"Sesuatu yang mudah terbakar atau mudah terpengaruh."},{"peribahasa":"bagai balam dengan ketitir","makna":"Sangat serasi atau cocok."},{"peribahasa":"bagai beliung dengan asahan","makna":"Sangat akrab dan tidak dapat dipisahkan."},{"peribahasa":"bagai bertemu alu dengan lesung, beras kita yang terserak, ayam orang yang kenyang","makna":"Orang lain yang mendapatkan keuntungan dari usaha kita."},{"peribahasa":"bagai bulan dengan matahari","makna":"Sangat serasi atau cocok."},{"peribahasa":"bagai dawat dengan kertas","makna":"Sangat akrab dan tidak dapat dipisahkan."},{"peribahasa":"bagai dulang dengan tudung saji","makna":"Sangat serasi atau cocok."},{"peribahasa":"bagai ilak bercerai dengan benang","makna":"Sesuatu yang tidak dapat dipisahkan."},{"peribahasa":"bagai inai dengan kuku","makna":"Sangat akrab dan tidak dapat dipisahkan."},{"peribahasa":"bagai kuku dengan daging","makna":"Sangat akrab dan tidak dapat dipisahkan."},{"peribahasa":"bagai kuku dengan isi","makna":"Sangat akrab dan tidak dapat dipisahkan."},{"peribahasa":"bagai menampung air dengan limas pesuk","makna":"Melakukan pekerjaan yang sia-sia."},{"peribahasa":"berkata-kata dengan lutut","makna":"Berbicara tanpa berpikir."},{"peribahasa":"berkelahi dengan orang tak berambut","makna":"Bertengkar dengan orang yang tidak memiliki apa-apa."},{"peribahasa":"berlayar bernakhoda, berjalan dengan yang tua","makna":"Setiap pekerjaan harus ada pemimpinnya."},{"peribahasa":"bersawah seperempat piring, ke sawah sama dengan orang","makna":"Meskipun sedikit, tetapi tetap ikut berpartisipasi."},{"peribahasa":"bersisih antah dengan beras","makna":"Memisahkan yang baik dari yang buruk."},{"peribahasa":"bersua baji dengan matan (tahan baji oleh kelidai)","makna":"Bertemu dengan lawan yang seimbang."},{"peribahasa":"bersua beliung dengan sangkal","makna":"Bertemu dengan lawan yang seimbang."},{"peribahasa":"bersukat darah, bertimbang daging (dengan)","makna":"Berjuang mati-matian."},{"peribahasa":"bertemu beliung dengan ruyung","makna":"Bertemu dengan lawan yang seimbang."},{"peribahasa":"bertemu muka dengan tedung","makna":"Bertemu dengan orang yang berbahaya."},{"peribahasa":"bertemu ruas dengan buku","makna":"Sesuatu yang sudah sesuai pada tempatnya."},{"peribahasa":"bertemu teras dengan beliung","makna":"Bertemu dengan lawan yang seimbang."},{"peribahasa":"bertukar beruk dengan cigak","makna":"Bertukar sesuatu yang sama saja nilainya."},{"peribahasa":"bertukar monyet dengan beruk","makna":"Bertukar sesuatu yang sama saja nilainya."},{"peribahasa":"cakap berlauk(-lauk), makan dengan sambal lada","makna":"Banyak bicara tetapi tidak ada isinya."},{"peribahasa":"campak bunga dibalas dengan campak tahi","makna":"Kebaikan dibalas dengan kejahatan."},{"peribahasa":"didenda dengan emas yang habis, dipancung dengan pedang yang hilang","makna":"Hukuman yang tidak adil."},{"peribahasa":"dimandikan dengan air segeluk","makna":"Sesuatu yang sangat sedikit."},{"peribahasa":"dengan sesendok madu dapat lebih banyak ditangkap serangga daripada dengan cuka sesendok","makna":"Kebaikan akan lebih mudah menarik orang daripada kekerasan."},{"peribahasa":"duduk dengan sukatan","makna":"Hidup hemat."},{"peribahasa":"gigi dengan lidah, adakalanya bergigit juga","makna":"Orang yang sangat dekat pun kadang-kadang bisa berselisih paham."},{"peribahasa":"hidup sandar-menyandar umpama aur dengan tebing","makna":"Saling membantu dan membutuhkan."},{"peribahasa":"hitam mata itu mana boleh bercerai dengan putihnya","makna":"Sesuatu yang tidak dapat dipisahkan."},{"peribahasa":"jangan dekatkan panggang dengan kucing","makna":"Jangan mendekatkan sesuatu yang mudah tergoda dengan godaan."},{"peribahasa":"jangan dicatuk dengan yang tajam, cincang dengan yang majal","makna":"Jangan melakukan sesuatu dengan cara yang salah."},{"peribahasa":"kalau kena tampar, biar dengan tangan yang pakai cincin, kalau kena tendang, biar dengan kaki yang pakai kasut","makna":"Jika dihukum, biarlah oleh orang yang berkuasa."},{"peribahasa":"kalau langit hendak menimpa bumi, bolehkah ditahan dengan telunjuk","makna":"Sesuatu yang besar dan tidak dapat dihindari."},{"peribahasa":"kasih tidak bersekutu dengan baik","makna":"Cinta yang tidak tulus."},{"peribahasa":"kepala tersangkut dengan kulit babi","makna":"Terjebak dalam masalah yang sulit."},{"peribahasa":"ketemu baji dengan matan","makna":"Bertemu dengan lawan yang seimbang."},{"peribahasa":"kusut ujung dengan pangkalnya","makna":"Masalah yang sangat rumit."},{"peribahasa":"malu-malu kucing, bujang dengan gadis","makna":"Berpura-pura malu, padahal mau."},{"peribahasa":"matahari itu bolehkah ditutup dengan nyiru","makna":"Sesuatu yang sudah jelas tidak dapat disembunyikan."},{"peribahasa":"memakuk dengan punggung lading","makna":"Melakukan sesuatu dengan cara yang tidak benar."},{"peribahasa":"membalas air susu dengan air tuba","makna":"Kebaikan dibalas dengan kejahatan."},{"peribahasa":"membasuh muka dengan air liur","makna":"Mempermalukan diri sendiri."},{"peribahasa":"membasuh najis dengan malu","makna":"Menutupi aib dengan aib yang lain."},{"peribahasa":"membungkus tulang dengan daun talas","makna":"Melakukan pekerjaan yang sia-sia."},{"peribahasa":"memikat balam dengan balam","makna":"Menggunakan sesuatu yang sejenis untuk mendapatkan sesuatu yang lain."},{"peribahasa":"menangis daun bangun-bangun hendak sama dengan hilir air","makna":"Seseorang yang ingin menyamai orang lain, tetapi tidak mampu."},{"peribahasa":"menangkap gajah liar itu dengan gajah juga","makna":"Menggunakan cara yang sepadan untuk menghadapi masalah besar."},{"peribahasa":"mencungkil kuman dengan alu","makna":"Melakukan pekerjaan yang tidak sesuai dengan alatnya."},{"peribahasa":"mengaut laba dengan siku","makna":"Mencari keuntungan dengan cara yang tidak jujur."},{"peribahasa":"menggaut laba dengan siku","makna":"Mencari keuntungan dengan cara yang tidak jujur."},{"peribahasa":"mengikat manusia dengan akal, mengikat binatang dengan tali","makna":"Manusia diatur dengan akal, binatang diatur dengan tali."},{"peribahasa":"menyisip padi dengan ilalang","makna":"Mencampur yang baik dengan yang buruk."},{"peribahasa":"minyak dengan air adakah (bolehkah) bercampur?","makna":"Dua hal yang tidak dapat bersatu."},{"peribahasa":"muka bagai ditampar dengan kulit babi","makna":"Sangat malu."},{"peribahasa":"mulut disuapi pisang, pantat dikait dengan onak (mulut manis hati berkait)","makna":"Perkataan manis yang menyembunyikan niat jahat."},{"peribahasa":"padi dikebat dengan daunnya","makna":"Sesuatu yang sudah teratur dan rapi."},{"peribahasa":"padi segenggam dengan senang hati lebih baik daripada padi selumbung dengan bersusah hati","makna":"Sedikit rezeki yang didapat dengan senang hati lebih baik daripada banyak rezeki yang didapat dengan susah hati."},{"peribahasa":"patah kemudi dengan bamnya","makna":"Rusak parah."},{"peribahasa":"patah kemudi dengan ebamnya","makna":"Rusak parah."},{"peribahasa":"pergi tempat bertanya, pulang tempat berberita (berkenaan dengan orang cerdik pandai)","makna":"Pergi untuk mencari ilmu, pulang untuk menyebarkan ilmu."},{"peribahasa":"pucuk diremas dengan santan, urat direndam dengan tengguli, lamun peria pahit juga","makna":"Sifat asli seseorang sulit diubah."},{"peribahasa":"sebagai aur dengan tebing","makna":"Saling membantu dan membutuhkan."},{"peribahasa":"sebagai dawat dengan kertas","makna":"Sangat akrab dan tidak dapat dipisahkan."},{"peribahasa":"sebagai garam dengan asam","makna":"Sangat serasi atau cocok."},{"peribahasa":"sebagai kunyit dengan kapur","makna":"Sangat serasi atau cocok."},{"peribahasa":"sebagai minyak dengan air","makna":"Dua hal yang tidak dapat bersatu."},{"peribahasa":"sedatar saja lurah dengan bukit","makna":"Sama rata."},{"peribahasa":"sendok dan periuk lagi berantuk (sendok dengan belanga lagi berlaga)","makna":"Orang yang sangat dekat pun kadang-kadang bisa berselisih paham."},{"peribahasa":"sepantun elang dengan ayam, lambat laun akan disambar jua","makna":"Yang kuat akan memangsa yang lemah."},{"peribahasa":"sepantun elang dengan ayam, lambat laun disambar juga","makna":"Yang kuat akan memangsa yang lemah."},{"peribahasa":"serigala dengan anggur","makna":"Sesuatu yang tidak cocok."},{"peribahasa":"seukur mata dengan telinga","makna":"Sesuatu yang seimbang."},{"peribahasa":"seperti anjing dengan kucing","makna":"Sering bertengkar."},{"peribahasa":"seperti birah dengan keladi","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti cembul dengan tutupnya (dapat tutupnya)","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti cincin dengan permata","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti daun delima dengan bunganya","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti durian dengan mentimun","makna":"Sesuatu yang tidak seimbang, yang satu kuat yang lain lemah."},{"peribahasa":"seperti gajah dengan sengkelanya","makna":"Sesuatu yang tidak dapat dipisahkan."},{"peribahasa":"seperti garuk dengan sisir","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti gerup dengan sisir","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti kedangkan dengan caping","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti kera dengan monyet","makna":"Sangat mirip."},{"peribahasa":"seperti keroncor dengan belangkas","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti lepat dengan daun","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti mentimun dengan durian","makna":"Sesuatu yang tidak seimbang, yang satu kuat yang lain lemah."},{"peribahasa":"seperti pinggan dengan mangkuk, salah sedikit, hendak berantuk","makna":"Orang yang sangat dekat pun kadang-kadang bisa berselisih paham."},{"peribahasa":"seperti rabuk dengan api","makna":"Sesuatu yang mudah terbakar atau mudah terpengaruh."},{"peribahasa":"seperti santan dengan tengguli","makna":"Sangat serasi atau cocok."},{"peribahasa":"seperti sayur dengan rumput","makna":"Sesuatu yang tidak seimbang."},{"peribahasa":"seperti siang dengan malam","makna":"Sesuatu yang sangat berbeda."},{"peribahasa":"susu dibalas dengan tuba","makna":"Kebaikan dibalas dengan kejahatan."},{"peribahasa":"tangguk lerek dengan bingkainya","makna":"Sangat serasi atau cocok."},{"peribahasa":"tentang mata dengan mata (antara empat mata)","makna":"Berbicara secara langsung dan jujur."}]');
