ribahasa":"sungguhpun kawat yang dibentuk, ikan di laut yang diadang","makna":"Meskipun sudah berusaha keras, tetapi hasilnya tidak sesuai harapan."},{"peribahasa":"tahu di angin berkisar","makna":"Mengetahui perubahan keadaan."},{"peribahasa":"tahu di angin turun naik","makna":"Mengetahui perubahan keadaan."},{"peribahasa":"tahu di asin garam","makna":"Mengetahui seluk beluk kehidupan."},{"peribahasa":"tahu di dalam lubuk","makna":"Mengetahui rahasia atau seluk beluk suatu perkara."},{"peribahasa":"tak (ber) pucuk di atas enau","makna":"Sesuatu yang tidak memiliki harapan."},{"peribahasa":"tak berpucuk di atas enau","makna":"Sesuatu yang tidak memiliki harapan."},{"peribahasa":"tak lapuk di hujan, tak lekang di panas","makna":"Sesuatu yang abadi."},{"peribahasa":"takut di hantu, terpeluk ke bangkai","makna":"Menghindari bahaya kecil, tetapi malah mendapatkan bahaya besar."},{"peribahasa":"tampak gabak di hulu (gabak di hulu tanda akan hujan)","makna":"Tanda-tanda akan terjadi sesuatu."},{"peribahasa":"tanduk di berkas","makna":"Sesuatu yang sudah pasti terjadi."},{"peribahasa":"tanduk di kepala tak dapat digelengkan","makna":"Sesuatu yang sudah menjadi takdir tidak dapat dihindari."},{"peribahasa":"tebu masuk di mulut gajah","makna":"Sesuatu yang sangat mudah."},{"peribahasa":"telaga di bawah gunung","makna":"Sesuatu yang sangat dalam."},{"peribahasa":"telur di ujung tanduk","makna":"Dalam keadaan sangat berbahaya."},{"peribahasa":"terconteng arang di muka","makna":"Mendapatkan malu atau aib yang sangat besar."},{"peribahasa":"tercoreng arang di dahi (kening, muka)","makna":"Mendapatkan malu atau aib yang sangat besar dan tidak dapat ditutupi lagi karena sudah diketahui oleh banyak orang."},{"peribahasa":"tergolek di nan datar","makna":"Sesuatu yang mudah didapatkan."},{"peribahasa":"terkalang di mata, terasa di hati","makna":"Sesuatu yang selalu teringat dan terasa di hati."},{"peribahasa":"terkilan di hati, terkalang di mata","makna":"Sesuatu yang selalu teringat