insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('51396', 'di.ma.kan', 'dimakan', '', 'makan¹', '["Verba","kiasan","Verba"]', '[{"nomor":"1","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"dimusnahkan; dirusakkan; dihabiskan","contoh":[{"nomor":2,"teks":"rumahnya habis ~ api"},{"nomor":4,"teks":"pagar besinya keropos ~ karat"}]},{"nomor":"2","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"mendapat penyakit: mendapat penyakit kulit, terutama di antara jari kaki karena bekerja di sawah","contoh":[{"nomor":2,"teks":"kakinya ~ air"}]}]', null, '[]', '["dimakan pakaian","dimakan peluru","dimakan sumpah","dimakan tikus","dimakan umur","dimakan usia"]', '["ada sama dimakan, tidak ada sama dicari","air diminum rasa duri, nasi dimakan rasa sekam","bagai ayam dimakan tungau","hitam, hitam tahi minyak dimakan juga, putih-putih ampas kelapa dibuang","ketika ada jangan dimakan, telah habis (tiada) maka dimakan","lagi ada jangan dimakan, sudah habis baru dimakan","makanan enggang akan dimakan pipit","nasi sama ditanak, kerak dimakan seorang","orang muda selendang dunia, orang kaya suka dimakan","padi selumbung dimakan orang banyak","rezeki elang tak akan dapat (dimakan) oleh musang (burung pipit)","sebusuk-busuk daging dikincah dimakan juga, seharum-harum tulang dibuang","tak lekang dimakan zaman","telah habis, maka dimakan","yang dimakan rasa, yang dilihat rupa, yang didengar bunyi"]', '["dimakan tikus","habis dimakan api"]', '[{"peribahasa":"ada sama dimakan, tidak ada sama dicari","makna":"Saling berbagi dalam suka dan duka."},{"peribahasa":"air diminum rasa duri, nasi dimakan rasa sekam","makna":"Sesuatu yang tidak enak."},{"peribahasa":"bagai ayam dimakan tungau","makna":"Seseorang yang tidak berdaya."},{"peribahasa":"hitam, hitam tahi minyak dimakan juga, putih-putih ampas kelapa dibuang","makna":"Sesuatu yang buruk tetapi bermanfaat, lebih baik daripada sesuatu yang baik tetapi tidak bermanfaat."},{"peribahasa":"ketika ada jangan dimakan, telah habis (tiada) maka dimakan","makna":"Sesuatu yang ada jangan disia-siakan, nanti menyesal jika sudah tidak ada."},{"peribahasa":"lagi ada jangan dimakan, sudah habis baru dimakan","makna":"Sesuatu yang ada jangan disia-siakan, nanti menyesal jika sudah tidak ada."},{"peribahasa":"makanan enggang akan dimakan pipit","makna":"Sesuatu yang besar akan dimakan oleh yang kecil."},{"peribahasa":"nasi sama ditanak, kerak dimakan seorang","makna":"Seseorang yang mengambil keuntungan sendiri."},{"peribahasa":"orang muda selendang dunia, orang kaya suka dimakan","makna":"Orang muda adalah harapan bangsa, orang kaya suka berfoya-foya."},{"peribahasa":"padi selumbung dimakan orang banyak","makna":"Sesuatu yang sedikit tetapi dinikmati oleh banyak orang."},{"peribahasa":"rezeki elang tak akan dapat (dimakan) oleh musang (burung pipit)","makna":"Setiap orang memiliki rezekinya masing-masing."},{"peribahasa":"sebusuk-busuk daging dikincah dimakan juga, seharum-harum tulang dibuang","makna":"Sesuatu yang buruk tetapi bermanfaat, lebih baik daripada sesuatu yang baik tetapi tidak bermanfaat."},{"peribahasa":"tak lekang dimakan zaman","makna":"Sesuatu yang abadi."},{"peribahasa":"telah habis, maka dimakan","makna":"Sesuatu yang ada jangan disia-siakan, nanti menyesal jika sudah tidak ada."},{"peribahasa":"yang dimakan rasa, yang dilihat rupa, yang didengar bunyi","makna":"Sesuatu yang dinilai dari penampilan luar."}]');
