insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('92350', 'dp', 'dp', '', '', '["Nomina","singkatan"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"sing","nama":"singkatan","tipe":"kelas_kata"}],"definisi":"daripada","contoh":[]}]', null, '[]', '[]', '["besar pasak daripada tiang","besar senggulung daripada beban, besar pasak daripada tiang","biar berputih tulang, jangan berputih mata (lebih baik berputih tulang daripada berputih mata)","dahulu bajak daripada jawi","dengan sesendok madu dapat lebih banyak ditangkap serangga daripada dengan cuka sesendok","daripada cempedak lebih baik nangka, daripada tidak, lebih baik ada","daripada hidup bercermin bangkai, lebih baik mati berkalang tanah","daripada hidup bercermin bangkai, lebih baik mati berkalang tanah (daripada hidup berlumur tahi, lebih baik mati bertimbun bunga)","imam yang adil lebih baik daripada hujan yang lebat","jika tiada tersapu arang di muka, baiklah mati daripada hidup","kalau sorok lebih dahulu daripada tokok, tidak mati babi","lebih baik mati berkalang tanah daripada hidup bercermin bangkai","lebih baik menyesal di hulu riam, daripada menyesal di hilir riam","lebih berharga mutiara sebutir daripada pasir sepantai","padi segenggam dengan senang hati lebih baik daripada padi selumbung dengan bersusah hati","seperti batang mengkudu, dahulu buah daripada bunga"]', '[]', '[{"peribahasa":"besar pasak daripada tiang","makna":"Pengeluaran lebih besar daripada penghasilan atau pendapatan; boros."},{"peribahasa":"besar senggulung daripada beban, besar pasak daripada tiang","makna":"Pengeluaran lebih besar daripada pendapatan."},{"peribahasa":"biar berputih tulang, jangan berputih mata (lebih baik berputih tulang daripada berputih mata)","makna":"Lebih baik mati daripada menanggung malu."},{"peribahasa":"dahulu bajak daripada jawi","makna":"Sesuatu yang seharusnya didahulukan malah dikemudiankan, dan sebaliknya; tidak mengikuti aturan yang biasa."},{"peribahasa":"dengan sesendok madu dapat lebih banyak ditangkap serangga daripada dengan cuka sesendok","makna":"Kebaikan akan lebih mudah menarik orang daripada kekerasan."},{"peribahasa":"daripada cempedak lebih baik nangka, daripada tidak, lebih baik ada","makna":"Sesuatu yang sedikit atau kurang baik pun lebih baik daripada tidak ada sama sekali."},{"peribahasa":"daripada hidup bercermin bangkai, lebih baik mati berkalang tanah","makna":"Lebih baik mati daripada menanggung malu yang sangat besar."},{"peribahasa":"daripada hidup bercermin bangkai, lebih baik mati berkalang tanah (daripada hidup berlumur tahi, lebih baik mati bertimbun bunga)","makna":"Lebih baik mati daripada menanggung malu yang sangat besar."},{"peribahasa":"imam yang adil lebih baik daripada hujan yang lebat","makna":"Keberadaan seorang pemimpin yang adil dan mampu menegakkan keadilan jauh lebih bermanfaat dan membersihkan masyarakat daripada hujan lebat sekalipun."},{"peribahasa":"jika tiada tersapu arang di muka, baiklah mati daripada hidup","makna":"Lebih baik mati daripada menanggung malu."},{"peribahasa":"kalau sorok lebih dahulu daripada tokok, tidak mati babi","makna":"Jika hanya mengandalkan lagak atau bual (omong besar) yang didahulukan tanpa disertai tindakan nyata, maka maksud atau tujuan yang diinginkan tidak akan tercapai."},{"peribahasa":"lebih baik mati berkalang tanah daripada hidup bercermin bangkai","makna":"Lebih baik mati daripada menanggung malu yang sangat besar."},{"peribahasa":"lebih baik menyesal di hulu riam, daripada menyesal di hilir riam","makna":"Lebih baik menyesal di awal daripada menyesal di akhir."},{"peribahasa":"lebih berharga mutiara sebutir daripada pasir sepantai","makna":"Sesuatu yang sedikit tetapi berkualitas lebih baik daripada banyak tetapi tidak berkualitas."},{"peribahasa":"padi segenggam dengan senang hati lebih baik daripada padi selumbung dengan bersusah hati","makna":"Sedikit rezeki yang didapat dengan senang hati lebih baik daripada banyak rezeki yang didapat dengan susah hati."},{"peribahasa":"seperti batang mengkudu, dahulu buah daripada bunga","makna":"Orang yang lekas marah sebelum mengetahui benar kesalahan orang yang hendak dimarahinya."}]');
