insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('20611', 'du.a', 'dua', '', '', '["Numeralia","Numeralia"]', '[{"nomor":"1","kelasKata":[{"kode":"num","nama":"Numeralia","tipe":"kelas_kata"}],"definisi":"bilangan yang dilambangkan dengan angka 2 (Arab) atau II (Romawi)","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"num","nama":"Numeralia","tipe":"kelas_kata"}],"definisi":"urutan ke-2 sesudah ke-1 dan sebelum ke-3","contoh":[]}]', null, '["berdua","berdua-dua","berduaan","dua-dua","dua-duaan","dua-duanya","keberduaan","kedua","kemenduaan","memperdua","memperduai","memperduakan","mendua","menduai","menduakan","menyedua","menyeduai","menyeduakan","pendua","penduaan","perdua","sedua","seperdua"]', '["dua dimensi","dua jempol"]', '["ayam satu bertambang dua","bagai belacan dikerat dua yang pergi bau busuk yang tinggal anyir","bagai kambing harga dua kupang","biduk satu nahkoda dua","cencang dua segerai","dua kali pisang berbuah","empat susu, dua perut","esa hilang, dua terbilang","gajah seekor, gembala dua","hidup dua muara","jung satu, nakhoda dua","kapal satu, nakhoda dua","kelam bagai malam dua puluh tujuh","kena pedang bermata dua","pelesit dua sejinjang","pisang tidak berbuah dua kali","satu nyawa, dua badan","satu sangkar, dua burung","sekali merengkuh dayung, dua tiga pulau terlampaui","seperti mawar di antara dua duri","sigai dua segeragai","seperti gergaji dua mata","seperti parang bermata dua","seperti pinang dibelah dua","talam dua muka","tarik muka dua belas"]', '["berpikir dua kali","dua sisi mata uang","menghunjamkan lutut nan dua"]', '[{"peribahasa":"ayam satu bertambang dua","makna":"Sesuatu yang tidak jelas kepemilikannya."},{"peribahasa":"bagai belacan dikerat dua yang pergi bau busuk yang tinggal anyir","makna":"Sesuatu yang tidak ada gunanya."},{"peribahasa":"bagai kambing harga dua kupang","makna":"Sesuatu yang tidak berharga."},{"peribahasa":"biduk satu nahkoda dua","makna":"Sesuatu yang tidak memiliki pemimpin yang jelas."},{"peribahasa":"cencang dua segerai","makna":"Sesuatu yang tidak rapi."},{"peribahasa":"dua kali pisang berbuah","makna":"Sesuatu yang terjadi dua kali."},{"peribahasa":"empat susu, dua perut","makna":"Sesuatu yang tidak seimbang."},{"peribahasa":"esa hilang, dua terbilang","makna":"Jika satu hilang, yang lain akan menggantikan."},{"peribahasa":"gajah seekor, gembala dua","makna":"Sesuatu yang tidak memiliki pemimpin yang jelas."},{"peribahasa":"hidup dua muara","makna":"Seseorang yang memiliki dua sumber penghasilan atau mata pencarian."},{"peribahasa":"jung satu, nakhoda dua","makna":"Suatu pekerjaan atau urusan yang dipimpin oleh dua orang, sehingga menimbulkan ketidakjelasan arah dan tujuan."},{"peribahasa":"kapal satu, nakhoda dua","makna":"Sama dengan \"jung satu, nakhoda dua\"."},{"peribahasa":"kelam bagai malam dua puluh tujuh","makna":"Suasana yang sangat gelap gulita dan mencekam."},{"peribahasa":"kena pedang bermata dua","makna":"Seseorang yang menderita kerugian atau celaka akibat perbuatannya sendiri yang merugikan orang lain."},{"peribahasa":"pelesit dua sejinjang","makna":"Dua orang (biasanya perempuan) yang selalu bersama-sama dan tidak terpisahkan."},{"peribahasa":"pisang tidak berbuah dua kali","makna":"Kesempatan baik tidak akan datang untuk kedua kalinya; oleh karena itu, manfaatkanlah kesempatan yang ada dengan sebaik-baiknya."},{"peribahasa":"satu nyawa, dua badan","makna":"Dua orang yang sangat akrab dan sehidup semati."},{"peribahasa":"satu sangkar, dua burung","makna":"Dua orang (biasanya laki-laki dan perempuan) yang saling mencintai dan tidak dapat dipisahkan."},{"peribahasa":"sekali merengkuh dayung, dua tiga pulau terlampaui","makna":"Mengerjakan beberapa pekerjaan sekaligus dalam satu waktu."},{"peribahasa":"seperti mawar di antara dua duri","makna":"Seorang wanita cantik yang berada di lingkungan yang tidak baik."},{"peribahasa":"sigai dua segeragai","makna":"Dua orang yang saling membantu dan bekerja sama dalam suka dan duka."},{"peribahasa":"seperti gergaji dua mata","makna":"Seseorang yang mendapat keuntungan dari kedua belah pihak yang berselisih."},{"peribahasa":"seperti parang bermata dua","makna":"Perkataan atau perbuatan yang dapat merugikan kedua belah pihak."},{"peribahasa":"seperti pinang dibelah dua","makna":"Dua orang yang sangat mirip, baik wajah maupun tingkah lakunya."},{"peribahasa":"talam dua muka","makna":"Orang yang berpihak kepada dua kubu yang berlawanan untuk keuntungan pribadi."},{"peribahasa":"tarik muka dua belas","makna":"Seseorang yang menunjukkan ekspresi wajah yang sangat masam atau tidak senang."}]');
